<body>
  <main class="app">
    <section class="topbar" aria-label="Game controls">
      <div class="title-block">
        <h1>Snake</h1>
        <p class="subtitle">Use the arrow keys to steer. Press Enter or use Restart to play again.</p>
      </div>
      <div class="hud">
        <div class="score-pill" aria-live="polite">Score <strong id="score">0</strong></div>
        <button id="restartButton" type="button">Restart</button>
      </div>
    </section>

    <section class="board-shell">
      <canvas id="game" width="600" height="600" aria-label="Snake game board"></canvas>
      <div class="overlay" id="gameOverOverlay" hidden>
        <div class="overlay-card">
          <h2>Game Over</h2>
          <p>Your final score was <strong id="finalScore">0</strong>.</p>
          <p>Press Enter or choose Restart to jump back in.</p>
          <button id="overlayRestartButton" type="button">Play Again</button>
        </div>
      </div>
    </section>

    <p class="status" id="statusText">Press any arrow key to begin.</p>
  </main>

  <script>
    const canvas = document.getElementById("game");
    const ctx = canvas.getContext("2d");
    const scoreEl = document.getElementById("score");
    const finalScoreEl = document.getElementById("finalScore");
    const statusEl = document.getElementById("statusText");
    const overlayEl = document.getElementById("gameOverOverlay");
    const restartButton = document.getElementById("restartButton");
    const overlayRestartButton = document.getElementById("overlayRestartButton");

    const gridSize = 20;
    const tileCount = canvas.width / gridSize;
    const tickMs = 120;

    const directionMap = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 }
    };

    let snake;
    let direction;
    let queuedDirection;
    let food;
    let score;
    let gameOver;
    let started;
    let tickHandle;

    function randomFoodPosition() {
      let nextFood;

      do {
        nextFood = {
          x: Math.floor(Math.random() * tileCount),
          y: Math.floor(Math.random() * tileCount)
        };
      } while (snake.some((segment) => segment.x === nextFood.x && segment.y === nextFood.y));

      return nextFood;
    }

    function setStatus(message) {
      statusEl.innerHTML = message;
    }

    function updateScore() {
      scoreEl.textContent = String(score);
      finalScoreEl.textContent = String(score);
    }

    function setGameOverState(isOver) {
      gameOver = isOver;
      overlayEl.hidden = !isOver;
      if (isOver) {
        setStatus("Hit <strong>Enter</strong> or choose <strong>Restart</strong> to play again.");
      }
    }

    function resetGame() {
      snake = [
        { x: 10, y: 10 },
        { x: 9, y: 10 },
        { x: 8, y: 10 }
      ];
      direction = { x: 1, y: 0 };
      queuedDirection = direction;
      score = 0;
      started = false;
      setGameOverState(false);
      food = randomFoodPosition();
      updateScore();
      setStatus("Press any arrow key to begin.");
      draw();
    }

    function drawBoard() {
      ctx.fillStyle = "#111827";
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.fillStyle = "#172033";
      for (let x = 0; x < tileCount; x += 1) {
        for (let y = 0; y < tileCount; y += 1) {
          if ((x + y) % 2 === 0) {
            ctx.fillRect(x * gridSize, y * gridSize, gridSize, gridSize);
          }
        }
      }
    }

    function drawFood() {
      const padding = 4;
      ctx.fillStyle = "#f97316";
      ctx.fillRect(
        food.x * gridSize + padding,
        food.y * gridSize + padding,
        gridSize - padding * 2,
        gridSize - padding * 2
      );
    }

    function drawSnake() {
      snake.forEach((segment, index) => {
        ctx.fillStyle = index === 0 ? "#4ade80" : "#22c55e";
        ctx.fillRect(
          segment.x * gridSize + 2,
          segment.y * gridSize + 2,
          gridSize - 4,
          gridSize - 4
        );
      });
    }

    function draw() {
      drawBoard();
      drawFood();
      drawSnake();
    }

    function isReverse(nextDirection) {
      return nextDirection.x === -direction.x && nextDirection.y === -direction.y;
    }

    function tick() {
      if (!started || gameOver) {
        return;
      }

      direction = queuedDirection;

      const head = {
        x: snake[0].x + direction.x,
        y: snake[0].y + direction.y
      };

      const hitWall =
        head.x < 0 ||
        head.y < 0 ||
        head.x >= tileCount ||
        head.y >= tileCount;

      const hitSelf = snake.some((segment) => segment.x === head.x && segment.y === head.y);

      if (hitWall || hitSelf) {
        setGameOverState(true);
        draw();
        return;
      }

      snake.unshift(head);

      if (head.x === food.x && head.y === food.y) {
        score += 1;
        updateScore();
        food = randomFoodPosition();
        setStatus("Score <strong>" + score + "</strong>. Keep going.");
      } else {
        snake.pop();
      }

      draw();
    }

    function startLoop() {
      if (tickHandle) {
        clearInterval(tickHandle);
      }
      tickHandle = setInterval(tick, tickMs);
    }

    function handleDirectionInput(key) {
      const nextDirection = directionMap[key];
      if (!nextDirection || gameOver) {
        return;
      }

      if (isReverse(nextDirection)) {
        return;
      }

      queuedDirection = nextDirection;

      if (!started) {
        started = true;
        setStatus("Stay alive.");
      }
    }

    document.addEventListener("keydown", (event) => {
      if (event.key in directionMap) {
        event.preventDefault();
        handleDirectionInput(event.key);
        return;
      }

      if ((event.key === "Enter" || event.key === " ") && gameOver) {
        event.preventDefault();
        resetGame();
      }
    });

    restartButton.addEventListener("click", resetGame);
    overlayRestartButton.addEventListener("click", resetGame);

    resetGame();
    startLoop();
  </script>
</body>
</html>
